LOCK TABLES `user_comments` WRITE;
/*!40000 ALTER TABLE `user_comments` DISABLE KEYS */;
INSERT INTO `user_comments` VALUES (1,'Clear Colors: The green text for points and grey badges for locked games make it very easy to understand match statuses at a glance.\r\nHelpful Time Zones: Showing the live clocks for different cities and the clear timezone warning is incredibly helpful for a global tournament.\r\nEasy to Read: The font choices and layout make it easy to tell the difference between match dates, team names, and stadium locations.\r\nSimple Menu: The menu options (like \"My Predictions\" and \"Leaderboard\") are straightforward and easy to understand.','2026-06-13 15:44:26.615891','emre'),(2,'What needs to be fixed karsim!\r\nHorizontal Scrolling: Having to scroll left and right to see the full match table and scores is clunky; it should stack vertically for mobile screens.\r\nBlocked Content: The bottom browser bar overlay blocks the lowest row of games and scores, making them impossible to read.\r\nMenu Overlap: The text and profile info in the blue side-menu overlap awkwardly, making the options hard to read.','2026-06-13 15:46:24.506098','emre');
/*!40000 ALTER TABLE `user_comments` ENABLE KEYS */;
UNLOCK TABLES;

